/* ============================================================
   SINCRONIZAÇÃO COM DATA ATUAL
   Calcula automaticamente os dias da semana corrente
============================================================ */
function calcularSemanaAtual(){
  const hoje = new Date();
  // Pegar segunda-feira da semana atual
  const diaSemana = hoje.getDay(); // 0=dom,1=seg,...,6=sab
  const seg = new Date(hoje);
  // Ajustar para segunda (se hoje for domingo, volta 6 dias; se seg=0, etc.)
  const diffParaSeg = diaSemana === 0 ? -6 : 1 - diaSemana;
  seg.setDate(hoje.getDate() + diffParaSeg);

  const dias = [];
  for(let i=0; i<7; i++){
    const d = new Date(seg);
    d.setDate(seg.getDate() + i);
    dias.push(d.getDate());
  }
  return dias; // [seg, ter, qua, qui, sex, sab, dom]
}

function getDiaSemanaHoje(){
  const d = new Date().getDay(); // 0=dom
  // mapear para id
  const map = {1:"seg",2:"ter",3:"qua",4:"qui",5:"sex",6:"sab",0:"dom"};
  return map[d];
}

const nums = calcularSemanaAtual();

/* ============================================================
   CULTO DO DOMINGO — identifica qual domingo do mês é o domingo
   desta semana e retorna o nome correto do culto noturno.

   1º domingo → CULTO DE SANTA CEIA
   2º domingo → CULTO DE MISSÕES
   3º domingo → CULTO DO DEFAD
   4º domingo → CULTO DO DEJAD
   5º domingo → CULTO DA FAMÍLIA  (meses com 5 domingos)
============================================================ */
function getCultoNomeDomingo(){
  const CULTOS_DOMINGO = [
    "CULTO DE SANTA CEIA",   // 1º
    "CULTO DE MISSÕES",      // 2º
    "CULTO DO DEFAD",        // 3º
    "CULTO DO DEJAD",        // 4º
    "CULTO DA FAMÍLIA"       // 5º (bônus)
  ];

  // Calcular a data do domingo desta semana
  const hoje = new Date();
  const diaSemana = hoje.getDay(); // 0=dom
  const diffParaDom = diaSemana === 0 ? 0 : 7 - diaSemana;
  const domingo = new Date(hoje);
  domingo.setDate(hoje.getDate() + diffParaDom);

  // Qual domingo do mês? Ex: dia 15 → Math.ceil(15/7) = 3º domingo
  const diaDom = domingo.getDate();
  const qualesDomingo = Math.ceil(diaDom / 7); // 1 a 5

  const idx = Math.min(qualesDomingo - 1, 4); // índice 0–4
  return CULTOS_DOMINGO[idx];
}

