let escalaMusica = {};
let pregacaoRnd  = {};
let diaAtivo     = null;
let drawerEvCnt  = 0;
let drawerMusicos = false;

function rnd(arr){ return arr[Math.floor(Math.random()*arr.length)]; }

/* ============================================================
   SISTEMA DE PRIORIDADE JUSTA

   Regras:
   1. BLOQUEIO IMEDIATO (regra dura):
      Quem tocou no culto anterior NÃO pode tocar no culto seguinte.
      Ex: tocou na SEG → bloqueado na QUA.
          tocou na QUA → bloqueado na SEX.
      O bloqueio é por PESSOA (não por instrumento): se Fabio tocou
      Bateria na SEG, ele não toca nada na QUA.

   2. PRIORIDADE (dentro dos não-bloqueados):
      Entre os candidatos disponíveis, tem prioridade quem tocou
      MENOS vezes na semana até aqui (quem não tocou = máxima prioridade).
      Empate → sorteio aleatório entre os empatados.

   3. FALLBACK: se todos os candidatos disponíveis forem bloqueados
      (pool vazio), o bloqueio é relaxado para garantir escala completa.

   4. DOMINGO: sorteio puro (mata-mata), sem bloqueios.

   5. Eventos extras inseridos no meio (TER, QUI, SAB):
      ao salvar, todos os cultos APÓS o novo evento recalculam
      para manter a justiça considerando o histórico atualizado.
============================================================ */

/**
 * Sorteia um músico para um instrumento em um culto específico,
 * respeitando as regras de prioridade e restrições.
 *
 * @param {string} inst - instrumento
 * @param {number} posicao - índice do culto na semana (0-based)
 * @param {boolean} isDomingo - se true, sorteio puro (mata-mata)
 * @param {Set} usadosHoje - músicos já escalados neste culto (evitar duplicata)
 * @param {Object[]} historicoAnterior - array de escalaMusica dos cultos anteriores
 */
function sortearMusico(inst, posicao, isDomingo, usadosHoje, historicoAnterior){
  const todos = MUSICOS[inst];

  // Domingo: completamente aleatório, mas evita a mesma pessoa em dois instrumentos no mesmo culto
  if(isDomingo){
    const candidatosDom = todos.filter(n => !usadosHoje.has(n));
    return rnd(candidatosDom.length ? candidatosDom : todos);
  }

  // Quem tocou no culto IMEDIATAMENTE ANTERIOR está BLOQUEADO (regra dura)
  // Coleta TODOS os nomes que apareceram no culto anterior (qualquer instrumento)
  const escalaAnterior = historicoAnterior.length > 0
    ? historicoAnterior[historicoAnterior.length - 1]
    : null;
  const bloqueadosAnterior = new Set(
    escalaAnterior ? Object.values(escalaAnterior).flat() : []
  );

  // Contar participações de cada músico em TODOS os cultos anteriores desta semana
  // (excluindo o culto imediatamente anterior, pois esses já estão bloqueados)
  const vezesTocou = {};
  todos.forEach(n => vezesTocou[n] = 0);
  historicoAnterior.forEach(escDia => {
    if(!escDia) return;
    Object.values(escDia).forEach(nome => {
      vezesTocou[nome] = (vezesTocou[nome] || 0) + 1;
    });
  });

  // 1º filtro: sem duplicata hoje E sem quem tocou no culto anterior (regra dura)
  let candidatos = todos.filter(n => !usadosHoje.has(n) && !bloqueadosAnterior.has(n));

  // Relaxar bloqueio só se literalmente não sobrar ninguém disponível
  if(!candidatos.length) candidatos = todos.filter(n => !usadosHoje.has(n));
  if(!candidatos.length) candidatos = [...todos];

  // Dentre os candidatos válidos, priorizar quem tocou MENOS vezes na semana
  // (quem não tocou nada = prioridade máxima)
  const minVezes = Math.min(...candidatos.map(n => vezesTocou[n] || 0));
  const poolPrioritario = candidatos.filter(n => (vezesTocou[n] || 0) === minVezes);

  return rnd(poolPrioritario);
}

/* ============================================================
   GERAR ESCALA — percorre todos os cultos em ordem cronológica
   e aplica o sistema de prioridade justa
============================================================ */
function gerarEscala(){
  escalaMusica = {};
  pregacaoRnd  = {};

  // Cultos com músicos habilitados e com eventos
  const diasCulto = TODOS_DIAS.filter(d => d.culto && d.eventos.length > 0);

  diasCulto.forEach((dia, idx) => {
    escalaMusica[dia.id] = {};

    // Histórico de escalas dos cultos anteriores desta semana
    const historicoAnterior = diasCulto
      .slice(0, idx)
      .map(d => escalaMusica[d.id] || null);

    // Domingo (4º ou mais): mata-mata puro
    const isDomingo = dia.id === "dom";

    const usadosHoje = new Set();

    // Sortear cada instrumento (em ordem aleatória para evitar bias)
    Object.keys(MUSICOS)
      .sort(() => Math.random() - 0.5)
      .forEach(inst => {
        const escolhido = sortearMusico(inst, idx, isDomingo, usadosHoje, historicoAnterior);
        escalaMusica[dia.id][inst] = escolhido;
        usadosHoje.add(escolhido);
      });
  });

  TODOS_DIAS.forEach(dia => {
    dia.eventos.forEach((ev, i) => {
      const key = dia.id + "-" + i;
      pregacaoRnd[key] = ev.pregacao || "";
    });
  });

  renderizar();
  atualizarDataBadge();
}

/**
 * Recalcula a escala apenas dos cultos a partir de um índice,
 * preservando os cultos anteriores (chamado quando um evento
 * extra é inserido no meio da semana).
 */
function recalcularAPartirDe(diaId){
  const diasCulto = TODOS_DIAS.filter(d => d.culto && d.eventos.length > 0);
  const startIdx  = diasCulto.findIndex(d => d.id === diaId);
  if(startIdx < 0) return;

  for(let idx = startIdx; idx < diasCulto.length; idx++){
    const dia = diasCulto[idx];
    const historicoAnterior = diasCulto
      .slice(0, idx)
      .map(d => escalaMusica[d.id] || null);
    const isDomingo = dia.id === "dom";
    const usadosHoje = new Set();

    escalaMusica[dia.id] = {};
    Object.keys(MUSICOS)
      .sort(() => Math.random() - 0.5)
      .forEach(inst => {
        const escolhido = sortearMusico(inst, idx, isDomingo, usadosHoje, historicoAnterior);
        escalaMusica[dia.id][inst] = escolhido;
        usadosHoje.add(escolhido);
      });
  }
  renderizar();
  atualizarDataBadge();
}

const MESES = ["JANEIRO","FEVEREIRO","MARÇO","ABRIL","MAIO","JUNHO","JULHO","AGOSTO","SETEMBRO","OUTUBRO","NOVEMBRO","DEZEMBRO"];
const DIAS_NOME = ["domingo","segunda-feira","terça-feira","quarta-feira","quinta-feira","sexta-feira","sábado"];

function atualizarDataBadge(){
  const hoje = new Date();
  const mes = MESES[hoje.getMonth()];
  const ano = hoje.getFullYear();
  const label = document.getElementById("mes-label");
  if(label) label.textContent = mes + " " + ano;
  const badge = document.getElementById("data-badge");
  if(badge) badge.innerHTML = `📅 ${formatarIntervaloSemana()} DE ${mes.toUpperCase()}`;
  const badgeMobile = document.getElementById("data-badge-mobile");
  if(badgeMobile) badgeMobile.innerHTML = `📅 ${formatarIntervaloSemana()} DE ${mes.toUpperCase()}`;
}

function formatarIntervaloSemana(){
  const seg = nums[0];
  const dom = nums[6];
  return `${seg} a ${dom}`;
}

/* ============================================================
   RENDERIZAR — CARDS WEB/MOBILE
============================================================ */
function renderizar(){
  const hojeId = getDiaSemanaHoje();
  const rows   = document.getElementById("rows");
  rows.innerHTML = "";

  const ICONS  = {"Baixo":"🎸","Teclado":"🎹","Guitarra":"🎸","Violão":"🎻","Bateria":"🥁","Vocal":"🎤"};
  const COLORS = {"Baixo":"#a78bfa","Teclado":"#00c896","Guitarra":"#fb923c","Violão":"#38bdf8","Bateria":"#f472b6","Vocal":"#f5c518"};
  const diasCultoAll = TODOS_DIAS.filter(d => d.culto && d.eventos.length > 0);

  DIAS_SEMANA().forEach((dia, animIdx) => {
    const vazio  = dia.eventos.length === 0;
    const ehHoje = dia.id === hojeId;

    // Build card
    const card = document.createElement("div");
    card.className = "day-card" + (vazio ? " vazio" : "") + (ehHoje ? " hoje" : "");
    card.style.animationDelay = (animIdx * 60) + "ms";

    // Day column
    const accentRgb = hexToRgb(dia.accent);
    let dayCol = `
      <div class="card-day" style="background:linear-gradient(160deg,rgba(${accentRgb},0.22) 0%,transparent 100%)">
        <div class="day-abbr">${dia.abbr}</div>
        <div class="day-num" style="color:${dia.accent}">${dia.num}</div>
        ${ehHoje ? '<div class="hoje-badge">HOJE</div>' : ''}
      </div>`;

    // Body
    let body = "";
    if(vazio){
      body = `<div class="sem-eventos">Sem eventos</div>`;
    } else {
      dia.eventos.forEach((ev, i) => {
        const key = dia.id + "-" + i;
        const pg  = pregacaoRnd[key] !== undefined ? pregacaoRnd[key] : ev.pregacao;
        const cls = ev.hl ? "event-name hl-" + ev.hl : "event-name";
        if(i > 0) body += `<div class="second-event">`;
        body += `<div class="event-time">${ev.hora}</div>`;
        body += `<div class="${cls}">${ev.nome}</div>`;
        if(pg) body += `<div class="pregacao obs-block">💬 <strong>${pg}</strong></div>`;
        if(i > 0) body += `</div>`;
      });
    }

    // Musicians
    if(dia.culto && !vazio && escalaMusica[dia.id]){
      const idxDia = diasCultoAll.findIndex(d => d.id === dia.id);
      const vezesMap = {};
      diasCultoAll.slice(0, idxDia).forEach(d => {
        if(!escalaMusica[d.id]) return;
        Object.values(escalaMusica[d.id]).forEach(nome => {
          vezesMap[nome] = (vezesMap[nome]||0) + 1;
        });
      });

      body += `<div class="musicos-section">`;
      Object.entries(escalaMusica[dia.id]).forEach(([inst, nome]) => {
        const cor  = COLORS[inst] || "#aaa";
        const ico  = ICONS[inst]  || "🎵";
        const n    = vezesMap[nome] || 0;
        const priorColor = dia.id === "dom" ? "#8ab4c8" : n === 0 ? "#00d4aa" : n === 1 ? "#f5c518" : "#fb923c";
        const priorLabel = dia.id === "dom" ? "MATA-MATA" : n === 0 ? "1ª VEZ" : `${n+1}ª VEZ`;
        body += `<span class="musico-badge" onclick="substituirMusico('${dia.id}','${inst}')" title="Clique para sortear outro">
          <span class="musico-icon">${ico}</span>
          <span class="musico-name">${nome}</span>
          <span class="musico-inst" style="color:${cor}">${inst}</span>
          <span class="musico-vez" style="color:${priorColor}">${priorLabel}</span>
        </span>`;
      });
      body += `</div>`;
    }

    // Hinos Domingo
    if(dia.id === "dom" && dia.hinos && dia.hinos.some(h => h.trim())){
      body += `<div class="hinos-block">`;
      body += `<div class="hinos-label">🎶 Hinos para ensaiar</div>`;
      dia.hinos.forEach((h, i) => {
        if(!h.trim()) return;
        body += `<div class="hino-item">
          <span class="hino-num">${i+1}</span>${h}
        </div>`;
      });
      body += `</div>`;
    }

    card.innerHTML = `<div class="card-inner">${dayCol}<div class="card-body">${body}</div></div>`;
    rows.appendChild(card);
  });
}

function hexToRgb(hex){
  const r = parseInt(hex.slice(1,3),16);
  const g = parseInt(hex.slice(3,5),16);
  const b = parseInt(hex.slice(5,7),16);
  return `${r},${g},${b}`;
}

/* ============================================================
   SUBSTITUIÇÃO MANUAL DE MÚSICO
   Respeita as regras de prioridade ao substituir manualmente
============================================================ */
function substituirMusico(diaId, inst){
  const atual     = escalaMusica[diaId][inst];
  const diasCulto = TODOS_DIAS.filter(d => d.culto && d.eventos.length > 0);
  const idx       = diasCulto.findIndex(d => d.id === diaId);

  const historicoAnterior = diasCulto
    .slice(0, idx)
    .map(d => escalaMusica[d.id] || null);

  const isDomingo  = diaId === "dom";

  // Usados hoje (exceto o atual que vamos substituir)
  const usadosHoje = new Set(Object.values(escalaMusica[diaId]));
  usadosHoje.delete(atual);

  const todos = MUSICOS[inst];

  let novo;
  if(isDomingo){
    // Mata-mata puro: qualquer músico exceto o atual
    let pool = todos.filter(n => n !== atual);
    if(!pool.length){ mostrarToast("Sem outros músicos disponíveis para " + inst); return; }
    novo = rnd(pool);
  } else {
    // Bloqueado = quem tocou no culto imediatamente anterior (qualquer instrumento)
    const escalaAnterior = historicoAnterior.length > 0
      ? historicoAnterior[historicoAnterior.length - 1]
      : null;
    const bloqueadosAnterior = new Set(
      escalaAnterior ? Object.values(escalaAnterior).flat() : []
    );

    const vezesTocou = {};
    todos.forEach(n => vezesTocou[n] = 0);
    historicoAnterior.forEach(escDia => {
      if(!escDia) return;
      Object.values(escDia).forEach(nome => {
        vezesTocou[nome] = (vezesTocou[nome] || 0) + 1;
      });
    });

    // Candidatos: excluir atual, duplicatas hoje, e bloqueados do culto anterior
    let candidatos = todos.filter(n => n !== atual && !usadosHoje.has(n) && !bloqueadosAnterior.has(n));
    if(!candidatos.length) candidatos = todos.filter(n => n !== atual && !usadosHoje.has(n));
    if(!candidatos.length) candidatos = todos.filter(n => n !== atual);

    if(!candidatos.length){
      mostrarToast("Sem outros músicos disponíveis para " + inst);
      return;
    }

    const minVezes = Math.min(...candidatos.map(n => vezesTocou[n] || 0));
    const pool = candidatos.filter(n => (vezesTocou[n] || 0) === minVezes);
    novo = rnd(pool);
  }

  escalaMusica[diaId][inst] = novo;
  renderizar();
  mostrarToast(`${inst}: ${atual} → ${novo} ✓`);
}

/* ============================================================
   DRAWER — EDITAR SEMANA COMPLETA
============================================================ */
function abrirDrawer(tabId){
  const tabsEl = document.getElementById("day-tabs");
  tabsEl.innerHTML = "";
  TODOS_DIAS.forEach(dia => {
    const btn = document.createElement("button");
    btn.className = "day-tab" +
      (dia.visible ? " visible-day" : "") +
      (dia.eventos.length > 0 ? " has-events" : "");
    btn.id = "tab-" + dia.id;
    btn.innerHTML = `
      <span class="tab-abbr">${dia.abbr}</span>
      <span class="tab-badge">${dia.eventos.length} ev.</span>`;
    btn.style.borderBottomColor = "transparent";
    btn.onclick = () => ativarTab(dia.id);
    tabsEl.appendChild(btn);
  });

  document.getElementById("drawer-overlay").classList.add("open");
  ativarTab(tabId || TODOS_DIAS[0].id);
}

function fecharDrawer(){ document.getElementById("drawer-overlay").classList.remove("open"); diaAtivo = null; }
function fecharDrawerFora(e){ if(e.target === document.getElementById("drawer-overlay")) fecharDrawer(); }

function ativarTab(diaId){
  diaAtivo = diaId;
  TODOS_DIAS.forEach(d => {
    const t = document.getElementById("tab-" + d.id);
    if(!t) return;
    t.classList.toggle("active", d.id === diaId);
    t.style.borderBottomColor = d.id === diaId ? d.accent : "transparent";
    t.style.color = d.id === diaId ? "#fff" : "";
  });
  renderizarDrawerBody(diaId);
}

